"""Special Isogenies (30pts) — degree-5 isogeny codomain Montgomery A.

E0: y^2 = x^3 + x mod 419. Compute 5-isogeny, convert to Montgomery form.
"""


# This file was *autogenerated* from the file solve.sage
from sage.all_cmdline import *   # import sage library

_sage_const_419 = Integer(419); _sage_const_1 = Integer(1); _sage_const_0 = Integer(0); _sage_const_5 = Integer(5); _sage_const_42 = Integer(42); _sage_const_100 = Integer(100); _sage_const_256 = Integer(256); _sage_const_2 = Integer(2); _sage_const_3 = Integer(3); _sage_const_4 = Integer(4)
p = _sage_const_419 
F = GF(p)
E0 = EllipticCurve(F, [_sage_const_1 , _sage_const_0 ])
print("#E0:", E0.order())

# Try multiple order-5 points to see all distinct codomains
order = E0.order()
cof = order // _sage_const_5 
seen_A = set()
seen_K = []
set_random_seed(_sage_const_42 )
for _ in range(_sage_const_100 ):
    R = E0.random_point()
    K = cof * R
    if K.order() == _sage_const_5  and K not in seen_K:
        seen_K.append(K)
        phi = E0.isogeny(K)
        E1 = phi.codomain()
        Em = E1.montgomery_model()
        A = Em.a_invariants()
        # Extract A from Montgomery: y^2 = x^3 + Ax^2 + x
        # Sage returns a1,a2,a3,a4,a6 where a2 = A
        print(f"  K={K}, Montgomery A = {A[_sage_const_1 ]}")
        seen_A.add(A[_sage_const_1 ])
print("Distinct A values:", seen_A)

phi = E0.isogeny(K)
E1 = phi.codomain()
print("E1 short Weierstrass:", E1)
print("j(E1):", E1.j_invariant())

# Convert to Montgomery form By^2 = x^3 + Ax^2 + x
# Montgomery: j = 256*(A^2 - 3)^3 / (A^2 - 4)
# Given the codomain's j-invariant we can back-solve for A.
# But easier: use Sage's built-in conversion if available.
# Try EllipticCurve.montgomery_model() if available
try:
    Em = E1.montgomery_model()
    print("Montgomery:", Em)
except Exception as e:
    print("no built-in montgomery_model:", e)
    # Manual: given j, solve for A
    j = E1.j_invariant()
    # 256(A^2 - 3)^3 = j*(A^2 - 4)
    R = PolynomialRing(F, names=('A',)); (A,) = R._first_ngens(1)
    poly = _sage_const_256 *(A**_sage_const_2  - _sage_const_3 )**_sage_const_3  - j*(A**_sage_const_2  - _sage_const_4 )
    roots = poly.roots()
    print("possible A values:", roots)

